pre.code:
[agent] interval = "10s" round_interval = true
[[inputs.opcua]] endpoint = "opc.tcp://<OPC_SERVER>:4840/freeopcua/server/" name = "opcua" security_policy = "None" security_mode = "None" auth_method = "Anonymous" [[inputs.opcua.nodes]] name = "esp1_pressure" namespace = "2" identifier_type = "s" identifier = "freeopcua.Tags.esp1.pressure" default_tags = { device = "esp1", parameter = "pressure" } [[inputs.opcua.nodes]] name = "esp1_temperature" namespace = "2" identifier_type = "s" identifier = "freeopcua.Tags.esp1.temperature" default_tags = { device = "esp1", parameter = "temperature" } [[inputs.opcua.nodes]] name = "pump1_pressure" namespace = "2" identifier_type = "s" identifier = "freeopcua.Tags.pump1.pressure" default_tags = { device = "pump1", parameter = "pressure" } [[inputs.opcua.nodes]] name = "pump1_temperature" namespace = "2" identifier_type = "s" identifier = "freeopcua.Tags.pump1.temperature" default_tags = { device = "pump1", parameter = "temperature" } [[inputs.opcua.nodes]] name = "pump2_pressure" namespace = "2" identifier_type = "s" identifier = "freeopcua.Tags.pump2.pressure" default_tags = { device = "pump2", parameter = "pressure" } [[inputs.opcua.nodes]] name = "pump2_temperature" namespace = "2" identifier_type = "s" identifier = "freeopcua.Tags.pump2.temperature" default_tags = { device = "pump2", parameter = "temperature" }
[[outputs.http]] url = "https://<SPLUNK_HOST>:8088/services/collector/raw" method = "POST" data_format = "json" insecure_skip_verify = true use_batch_format = false [outputs.http.headers] Authorization = "Splunk <TOKEN>" Content-Type = "application/json"
